    public Dictionary<int, string> PlayerNames { get; private set; } = [];
    public int CurrentPlayer { get; private set; } = 1;
    public int TotalPlayers => PlayerScores.Count;
    public JeopardyQuestion? CurrentQuestion { get; private set; }
    public List<string> SelectedCategories { get; private set; } = [];
    public bool GameStarted { get; private set; } = false;
    public bool TimedModeEnabled { get; private set; } = true;

    private static readonly Random _random = new();
    private static readonly int[] ExpectedPointValues = [100, 200, 300, 400, 500];
    private const int MinDailyDoubleCountPerGame = 3;
    private const int MaxDailyDoubleCountPerGame = 6;
    private int _nextPlayerId = 1;
    public static readonly string[] AllCategoryNames = BuildCategoryNames();
    public static readonly string[] CompleteCategoryNames = BuildCompleteCategoryNames();
    private static string Canon(string s) => (s ?? "").Trim();

    public JeopardyGameService()
    {
        InitializePlayers();
    }

    private void InitializePlayers()
    {
        PlayerScores.Clear();
        PlayerNames.Clear();
        _nextPlayerId = 1;

        for (int i = 0; i < 3; i++)
        {
            AddPlayer();
        }
        CurrentPlayer = 1;
    }

    public void SetSelectedCategories(List<string> categories)
    {
        var canonicalCompleteMap = CompleteCategoryNames
            .ToDictionary(c => Canon(c), c => c, StringComparer.OrdinalIgnoreCase);

        var selected = categories
            .Select(c => Canon(c ?? ""))
            .Where(c => canonicalCompleteMap.ContainsKey(c))
            .Select(c => canonicalCompleteMap[c])
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .Take(6)
            .ToList();

        if (selected.Count < 6)
        {
            var needed = 6 - selected.Count;
            var fillers = CompleteCategoryNames
                .Where(c => !selected.Contains(c, StringComparer.OrdinalIgnoreCase))
                .OrderBy(_ => _random.Next())
                .Take(needed);
            selected.AddRange(fillers);
        }

        SelectedCategories = selected.Take(6).ToList();
    }

    public void SetTimedMode(bool enabled)
    {
        TimedModeEnabled = enabled;
    }

    public void StartGame()
    {
        if (SelectedCategories.Count == 0)
        {
            // Default categories if none selected
            SelectedCategories = CompleteCategoryNames
                .OrderBy(_ => _random.Next())
                .Take(6)
                .ToList();
        }

        // Defensive: Ensure at least one player exists
        if (PlayerScores.Count == 0)
        {
            AddPlayer();
        }

        foreach (var key in PlayerScores.Keys.ToList())
        {
            PlayerScores[key] = 0;
        }
        CurrentPlayer = PlayerScores.Keys.First();
        Categories = BuildGameBoard();
        GameStarted = true;
    }

    public void ResetToMenu()
    {
        GameStarted = false;
        Categories.Clear();
        foreach (var key in PlayerScores.Keys.ToList())
        {
            PlayerScores[key] = 0;
        }
    }

    public void InitializeGameKeepPlayers()
    {
        foreach (var key in PlayerScores.Keys.ToList())
        {
            PlayerScores[key] = 0;
        }
        CurrentPlayer = PlayerScores.Keys.First();
        Categories = BuildGameBoard();
    }

    public int AddPlayer(string? name = null)
    {
        int playerId = _nextPlayerId++;
        PlayerScores[playerId] = 0;
        PlayerNames[playerId] = name ?? $"Player {playerId}";
        return playerId;
    }

    public bool RemovePlayer(int playerId)
    {
        if (TotalPlayers <= 1) return false;

        if (PlayerScores.Remove(playerId))
        {
            PlayerNames.Remove(playerId);
            if (CurrentPlayer == playerId || !PlayerScores.ContainsKey(CurrentPlayer))
            {
                CurrentPlayer = PlayerScores.Keys.First();
            }
            return true;
        }
        return false;
    }

    public List<int> GetPlayerIds()
    {
        return PlayerScores.Keys.OrderBy(k => k).ToList();
    }

    private List<JeopardyCategory> BuildGameBoard()
    {
        var pool = GetAllQuestionPool();
        DebugValidateQuestionPool(pool);

        var allQuestions = pool;
        var categories = new List<JeopardyCategory>();
        var pointValues = new[] { 100, 200, 300, 400, 500 };

        foreach (var categoryName in SelectedCategories)
        {
            var categoryQuestions = allQuestions
                .Where(q => string.Equals(Canon(q.Category ?? ""), Canon(categoryName), StringComparison.OrdinalIgnoreCase))
                .GroupBy(q => q.PointValue)
                .ToDictionary(g => g.Key, g => g.ToList());

            var selectedQuestions = new List<JeopardyQuestion>();

            foreach (var pointValue in pointValues)
            {
                if (categoryQuestions.TryGetValue(pointValue, out var questionsForValue) && questionsForValue.Count > 0)
                {
                    var randomIndex = _random.Next(questionsForValue.Count);
                    var templateQuestion = questionsForValue[randomIndex];
                    selectedQuestions.Add(new JeopardyQuestion
                    {
                        Category = templateQuestion.Category,
                        PointValue = templateQuestion.PointValue,
                        Question = templateQuestion.Question,
                        Answer = templateQuestion.Answer,
                        IsAnswered = false,
                        IsBonus = false
                    });
                }
                else
                {
                    // Defensive: Add a placeholder question if missing
                    selectedQuestions.Add(new JeopardyQuestion
                    {
                        Category = categoryName,
                        PointValue = pointValue,
                        Question = $"No question available for {categoryName} ({pointValue} points).",
                        Answer = "N/A",
                        IsAnswered = false,
                        IsBonus = false
                    });
                }
            }

            categories.Add(new JeopardyCategory
            {
                Name = categoryName,
                Questions = selectedQuestions
            });
        }

        AssignDailyDoubles(categories);
        return categories;
    }

    private void AssignDailyDoubles(List<JeopardyCategory> categories)
    {
        var boardQuestions = categories.SelectMany(c => c.Questions).ToList();
        if (boardQuestions.Count == 0)
        {
            return;
        }

        int minDailyDoubleCount = Math.Min(MinDailyDoubleCountPerGame, boardQuestions.Count);
        int maxDailyDoubleCount = Math.Min(MaxDailyDoubleCountPerGame, boardQuestions.Count);
        int dailyDoubleCount = _random.Next(minDailyDoubleCount, maxDailyDoubleCount + 1);

        var randomizedQuestions = boardQuestions
            .OrderBy(_ => _random.Next())
            .ToList();

        for (int i = 0; i < dailyDoubleCount; i++)
        {
            randomizedQuestions[i].IsBonus = true;
        }
    }

    public void SetPlayerName(int playerNumber, string name)
    {
        if (PlayerNames.ContainsKey(playerNumber) && !string.IsNullOrWhiteSpace(name))
        {
            PlayerNames[playerNumber] = name;
        }
    }

    public void SelectQuestion(JeopardyQuestion question)
    {
        if (!question.IsAnswered)
        {
            CurrentQuestion = question;
        }
    }

    public void AnswerQuestion(bool isCorrect, int playerNumber)
    {
        if (CurrentQuestion != null && PlayerScores.ContainsKey(playerNumber))
        {
            CurrentQuestion.IsAnswered = true;
            int points = CurrentQuestion.IsBonus ? CurrentQuestion.PointValue * 2 : CurrentQuestion.PointValue;

            if (isCorrect)
                PlayerScores[playerNumber] += points;
            else
                PlayerScores[playerNumber] -= points;

            CurrentQuestion = null;
            NextPlayer();
        }
    }

    public void NextPlayer()
    {
        var playerIds = GetPlayerIds();
        int currentIndex = playerIds.IndexOf(CurrentPlayer);
        int nextIndex = (currentIndex + 1) % playerIds.Count;
        CurrentPlayer = playerIds[nextIndex];
    }
    public List<int> PlayerAttempts { get; private set; } = new();
public int? AnsweringPlayer { get; private set; } = null;
public string? PlayerAnswerInput { get; set; } = null;

public void StartPlayerAttempt(int playerId)
{
    if (CurrentQuestion != null && !PlayerAttempts.Contains(playerId))
    {
        PlayerAttempts.Add(playerId);
        AnsweringPlayer = playerId;
        PlayerAnswerInput = null;
    }
}
public void SubmitPlayerAnswer(string answer)
{
    PlayerAnswerInput = answer;
}

public void ScorePlayerAnswer(bool isCorrect)
{
    if (CurrentQuestion != null && AnsweringPlayer.HasValue)
    {
        CurrentQuestion.IsAnswered = true;
        int points = CurrentQuestion.IsBonus ? CurrentQuestion.PointValue * 2 : CurrentQuestion.PointValue;
        if (isCorrect)
            PlayerScores[AnsweringPlayer.Value] += points;
        else
            PlayerScores[AnsweringPlayer.Value] -= points;
        CurrentQuestion = null;
        AnsweringPlayer = null;
        PlayerAnswerInput = null;
        PlayerAttempts.Clear();
        NextPlayer();
    }
}

public void CloseQuestion()
{
    CurrentQuestion = null;
    AnsweringPlayer = null;
    PlayerAnswerInput = null;
    PlayerAttempts.Clear();
}

    public bool IsGameComplete() => Categories.All(c => c.Questions.All(q => q.IsAnswered));

    public int GetWinner() => PlayerScores.OrderByDescending(p => p.Value).First().Key;

    public int GetHighestScore() => PlayerScores.Values.Max();

    public static void ValidateQuestionPool()
    {
        ValidateQuestionPool(GetAllQuestionPool());
    }

    private static string[] BuildCategoryNames()
    {
        var pool = GetAllQuestionPool();
        DebugValidateQuestionPool(pool);

        return pool
            .Select(q => Canon(q.Category ?? ""))
            .Where(c => !string.IsNullOrWhiteSpace(c))
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .OrderBy(category => category, StringComparer.OrdinalIgnoreCase)
            .ToArray();
    }

    private static string[] BuildCompleteCategoryNames()
    {
        var pool = GetAllQuestionPool();
        DebugValidateQuestionPool(pool);

        return pool
            .GroupBy(q => Canon(q.Category ?? ""), StringComparer.OrdinalIgnoreCase)
            .Where(g =>
                !string.IsNullOrWhiteSpace(g.Key) &&
                g.Count() == 25 &&
                ExpectedPointValues.All(v => g.Count(q => q.PointValue == v) == 5))
            .Select(g => Canon(g.Key))
            .OrderBy(category => category, StringComparer.OrdinalIgnoreCase)
            .ToArray();
    }

    public static bool IsCategoryComplete(string? categoryName)
    {
        if (string.IsNullOrWhiteSpace(categoryName))
        {
            return false;
        }

        var canonicalCategory = Canon(categoryName);
        return CompleteCategoryNames.Contains(canonicalCategory, StringComparer.OrdinalIgnoreCase);
    }

    private static void ValidateQuestionPool(List<JeopardyQuestion> pool)
    {
        var issues = GetQuestionPoolIssues(pool);
        if (issues.Count == 0) return;

        var message = "Question pool validation failed:\n" + string.Join("\n", issues);
        throw new InvalidOperationException(message);
    }

    [Conditional("DEBUG")]
    private static void DebugValidateQuestionPool(List<JeopardyQuestion> pool)
    {
        foreach (var issue in GetQuestionPoolIssues(pool))
        {
            Console.WriteLine("[DEBUG] {0}", issue);
        }
    }

    private static List<string> GetQuestionPoolIssues(List<JeopardyQuestion> pool)
    {
        return pool
            .GroupBy(q => Canon(q.Category ?? ""), StringComparer.OrdinalIgnoreCase)
            .OrderBy(g => g.Key, StringComparer.OrdinalIgnoreCase)
            .Select(g =>
            {
                var counts = g.GroupBy(x => x.PointValue).ToDictionary(x => x.Key, x => x.Count());
                var duplicateQuestionCount = g
                    .GroupBy(x => Canon(x.Question ?? ""), StringComparer.OrdinalIgnoreCase)
                    .Count(x => x.Count() > 1);

                var parts = new List<string>();

                if (g.Count() < 25) parts.Add($"too few questions (found {g.Count()}, expected 25)");
                if (g.Count() > 25) parts.Add($"too many questions (found {g.Count()}, expected 25)");

                foreach (int tier in ExpectedPointValues)
                {
                    if (!counts.TryGetValue(tier, out int count))
                    {
                        parts.Add($"missing tier {tier}");
                    }
                    else if (count < 5)
                    {
                        parts.Add($"tier {tier} has too few (found {count}, expected 5)");
                    }
                    else if (count > 5)
                    {
                        parts.Add($"tier {tier} has too many (found {count}, expected 5)");
                    }
                }

                if (duplicateQuestionCount > 0)
                {
                    parts.Add($"duplicate question text count={duplicateQuestionCount}");
                }

                if (parts.Count == 0)
                {
                    return null;
                }

                return $"{g.Key}: {string.Join("; ", parts)}";
            })
            .Where(issue => issue is not null)
            .Cast<string>()
            .ToList();
    }

